import { inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';

interface Product { id: number; name: string; price: number; }

export class ProductService {
  private http = inject(HttpClient);

  async getProduct(id: number): Promise<Product> {
    return firstValueFrom(this.http.get<Product>(`/api/products/${id}`));
  }

  async loadAll(): Promise<Product[]> {
    return firstValueFrom(this.http.get<Product[]>('/api/products'));
  }
}

@Component({
  template: `
    @if (loading) { <p>Loading...</p> }
    @else if (error) { <p class="error">{{ error }}</p> }
    @else { <ul>@for (p of products; track p.id) { <li>{{ p.name }}</li> }</ul> }
  `
})
export class ProductListComponent implements OnInit {
  products: Product[] = [];
  loading = true;
  error = '';
  private svc = inject(ProductService);

  async ngOnInit() {
    try {
      this.products = await this.svc.loadAll();
    } catch (err) {
      this.error = (err as Error).message;
    } finally {
      this.loading = false;
    }
  }
}

import { ResolveFn } from '@angular/router';
import { inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';

export const productDetailResolver: ResolveFn<{ product: Product; reviews: Review[] }> =
  async (route) => {
    const http = inject(HttpClient);
    const id   = Number(route.paramMap.get('id'));

    const [product, reviews] = await Promise.all([
      firstValueFrom(http.get<Product>(`/api/products/${id}`)),
      firstValueFrom(http.get<Review[]>(`/api/products/${id}/reviews`)),
    ]);

    return { product, reviews };
  };

import { fakeAsync, flushMicrotasks, TestBed } from '@angular/core/testing';
import { provideHttpClient } from '@angular/common/http';
import { provideHttpClientTesting, HttpTestingController } from '@angular/common/http/testing';

describe('ProductService', () => {
  let service: ProductService;
  let http: HttpTestingController;

  beforeEach(() => {
    TestBed.configureTestingModule({
      providers: [ProductService, provideHttpClient(), provideHttpClientTesting()],
    });
    service = TestBed.inject(ProductService);
    http = TestBed.inject(HttpTestingController);
  });

  afterEach(() => http.verify());

  it('resolves with parsed data', async () => {
    const mock: Product = { id: 1, name: 'Widget', price: 9.99 };
    const promise = service.getProduct(1);
    http.expectOne('/api/products/1').flush(mock);
    expect(await promise).toEqual(mock);
  });

  it('rejects on HTTP error', async () => {
    const promise = service.getProduct(999);
    http.expectOne('/api/products/999')
      .flush('Not found', { status: 404, statusText: 'Not Found' });
    await expectAsync(promise).toBeRejected();
  });
});

// Microtask ordering with fakeAsync
it('microtasks flush before setTimeout', fakeAsync(() => {
  const order: string[] = [];
  Promise.resolve().then(() => order.push('microtask'));
  setTimeout(() => order.push('macrotask'), 0);

  flushMicrotasks();
  expect(order).toEqual(['microtask']);
  tick(0);
  expect(order).toEqual(['microtask', 'macrotask']);
}));

// SEQUENTIAL — each await waits for the previous to finish
// Total time = user time + posts time + prefs time
async function loadSequential(id: number) {
  const user  = await fetchUser(id);      // starts after nothing
  const posts = await fetchPosts(id);     // starts after user
  const prefs = await fetchPrefs(id);     // starts after posts
  return { user, posts, prefs };
}

// PARALLEL — all three start immediately
// Total time = max(user, posts, prefs)
async function loadParallel(id: number) {
  const [user, posts, prefs] = await Promise.all([
    fetchUser(id),
    fetchPosts(id),
    fetchPrefs(id),
  ]);
  return { user, posts, prefs };
}

// WATERFALL — second request depends on first result
async function loadWaterfall(id: number) {
  const user  = await fetchUser(id);         // must complete first
  const posts = await fetchPosts(user.id);   // needs user.id
  return { user, posts };
}

