// Angular example: deferred initialization
@Injectable({ providedIn: 'root' })
export class ConfigService {
  private readonly _ready = Promise.withResolvers<Config>();
  readonly ready = this._ready.promise;

  async load() {
    const cfg = await firstValueFrom(inject(HttpClient).get<Config>('/api/config'));
    this._ready.resolve(cfg);
    return cfg;
  }
}
